  `sektor_seciniz` VARCHAR(500),
  `yil` BIGINT,
  `11_sutun` TEXT,
  `12_sutun` TEXT,
  `13_sutun` TEXT,
  `14_sutun` TEXT,
  `15_sutun` TEXT,
  `16_sutun` TEXT,
  `17_sutun` TEXT,
  `18_sutun` TEXT,
  `19_sutun` TEXT,
  `20_sutun` TEXT,
  `21_sutun` TEXT,
  `22_sutun` TEXT,
  `created_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP
